// ── insertRun ─────────────────────────────────────────────────

describe('insertRun', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('inserts a run row with all fields', () => {
    const run = makeRun({
      id: 'run-insert-001',
      specPath: 'specs/auth.md',
      model: 'claude-opus-4-5',
      status: 'success',
      costUsd: 1.23,
      durationSeconds: 45.6,
      numTurns: 12,
      toolCalls: 8,
      batchId: 'batch-abc',
      type: 'run',
      prompt: 'build auth feature',
      cwd: '/projects/app',
      sessionId: 'sess-abc123',
      error: null,
      createdAt: '2026-01-01T10:00:00.000Z',
    });
    insertRun(db, run);

    const result = db.query('SELECT * FROM runs WHERE id = ?').get('run-insert-001') as RunRow;
    expect(result).not.toBeNull();
    expect(result.specPath).toBe('specs/auth.md');
    expect(result.costUsd).toBe(1.23);
    expect(result.durationSeconds).toBe(45.6);
    expect(result.batchId).toBe('batch-abc');
    expect(result.sessionId).toBe('sess-abc123');
    expect(result.createdAt).toBe('2026-01-01T10:00:00.000Z');
  });

  test('INSERT OR IGNORE is idempotent', () => {
    const run = makeRun({ id: 'run-idem-001', status: 'success' });
    insertRun(db, run);
    insertRun(db, { ...run, status: 'error_execution' }); // same id, different status

    const result = db.query('SELECT status FROM runs WHERE id = ?').get('run-idem-001') as { status: string };
    expect(result.status).toBe('success'); // original value preserved
  });

  test('allows null specPath (ad-hoc run without spec)', () => {
    const run = makeRun({ id: 'run-no-spec', specPath: null });
    insertRun(db, run);
    const result = db.query('SELECT specPath FROM runs WHERE id = ?').get('run-no-spec') as { specPath: string | null };
    expect(result.specPath).toBeNull();
  });

  test('stores error message when provided', () => {
    const run = makeRun({ id: 'run-with-error', status: 'error_execution', error: 'Verification failed after 3 attempts' });
    insertRun(db, run);
    const result = db.query('SELECT error FROM runs WHERE id = ?').get('run-with-error') as { error: string | null };
    expect(result.error).toBe('Verification failed after 3 attempts');
  });
});

// ── queryAggregateStats ──────────────────────────────────────

describe('queryAggregateStats', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('returns zeros for empty table', () => {
    const stats = queryAggregateStats(db);
    expect(stats.total).toBe(0);
    // SUM() returns null for empty tables in SQLite — treat null as 0
    expect(stats.passed ?? 0).toBe(0);
    expect(stats.failed ?? 0).toBe(0);
    expect(stats.totalCost).toBe(0); // COALESCE applied in query
    expect(stats.totalDuration).toBe(0); // COALESCE applied in query
  });

  test('counts total, passed, and failed correctly', () => {
    insertRun(db, makeRun({ id: 'r1', status: 'success', costUsd: 0.10, durationSeconds: 10 }));
    insertRun(db, makeRun({ id: 'r2', status: 'success', costUsd: 0.20, durationSeconds: 20 }));
    insertRun(db, makeRun({ id: 'r3', status: 'error_execution', costUsd: 0.05, durationSeconds: 5 }));

    const stats = queryAggregateStats(db);
    expect(stats.total).toBe(3);
    expect(stats.passed).toBe(2);
    expect(stats.failed).toBe(1);
    expect(stats.totalCost).toBeCloseTo(0.35);
    expect(stats.totalDuration).toBe(35);
  });

  test('--since filters by createdAt using lexicographic comparison', () => {
    insertRun(db, makeRun({ id: 'r-old', createdAt: '2025-01-01T00:00:00Z', status: 'success', costUsd: 0.10 }));
    insertRun(db, makeRun({ id: 'r-new', createdAt: '2026-03-01T00:00:00Z', status: 'success', costUsd: 0.20 }));

    const stats = queryAggregateStats(db, '2026-01-01T00:00:00Z');
    expect(stats.total).toBe(1);
    expect(stats.totalCost).toBeCloseTo(0.20);
  });

  test('handles null costUsd gracefully (COALESCE to 0)', () => {
    insertRun(db, makeRun({ id: 'r-no-cost', costUsd: null }));
    const stats = queryAggregateStats(db);
    expect(stats.totalCost).toBe(0);
  });

  test('sums numTurns correctly', () => {
    insertRun(db, makeRun({ id: 'r-t1', numTurns: 5 }));
    insertRun(db, makeRun({ id: 'r-t2', numTurns: 10 }));
    insertRun(db, makeRun({ id: 'r-t3', numTurns: null }));

    const stats = queryAggregateStats(db);
    expect(stats.totalTurns).toBe(15);
    expect(stats.runsWithTurns).toBe(2);
  });
});

// ── querySpecStats ────────────────────────────────────────────

describe('querySpecStats', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('groups by specPath', () => {
    insertRun(db, makeRun({ id: 'r1', specPath: 'specs/auth.md', status: 'success', costUsd: 0.10 }));
    insertRun(db, makeRun({ id: 'r2', specPath: 'specs/auth.md', status: 'success', costUsd: 0.20 }));
    insertRun(db, makeRun({ id: 'r3', specPath: 'specs/db.md', status: 'error_execution', costUsd: 0.05 }));

    const rows = querySpecStats(db);
    expect(rows.length).toBe(2);

    const authRow = rows.find(r => r.specPath === 'specs/auth.md');
    expect(authRow).toBeDefined();
    expect(authRow!.runs).toBe(2);
    expect(authRow!.passed).toBe(2);
    expect(authRow!.avgCost).toBeCloseTo(0.15);

    const dbRow = rows.find(r => r.specPath === 'specs/db.md');
    expect(dbRow!.runs).toBe(1);
    expect(dbRow!.passed).toBe(0);
  });

  test('excludes runs with null specPath', () => {
    insertRun(db, makeRun({ id: 'r1', specPath: null }));
    insertRun(db, makeRun({ id: 'r2', specPath: 'specs/test.md' }));

    const rows = querySpecStats(db);
    expect(rows.length).toBe(1);
    expect(rows[0].specPath).toBe('specs/test.md');
  });

  test('orders by runs DESC (most-run specs first)', () => {
    insertRun(db, makeRun({ id: 'r1', specPath: 'specs/a.md' }));
    insertRun(db, makeRun({ id: 'r2', specPath: 'specs/b.md' }));
    insertRun(db, makeRun({ id: 'r3', specPath: 'specs/b.md' }));
    insertRun(db, makeRun({ id: 'r4', specPath: 'specs/b.md' }));

    const rows = querySpecStats(db);
    expect(rows[0].specPath).toBe('specs/b.md'); // 3 runs
    expect(rows[1].specPath).toBe('specs/a.md'); // 1 run
  });

  test('--since filters by createdAt', () => {
    insertRun(db, makeRun({ id: 'r-old', specPath: 'specs/old.md', createdAt: '2025-01-01T00:00:00Z' }));
    insertRun(db, makeRun({ id: 'r-new', specPath: 'specs/new.md', createdAt: '2026-03-01T00:00:00Z' }));

    const rows = querySpecStats(db, '2026-01-01T00:00:00Z');
    expect(rows.length).toBe(1);
    expect(rows[0].specPath).toBe('specs/new.md');
  });
});

