describe('queryStatusRuns', () => {
  let db: Database;

  beforeEach(() => {
    db = getTestDb();
  });

  test('returns runs ordered by createdAt DESC', () => {
    insertRun(db, makeRun({ id: 'r-first', createdAt: '2026-01-01T10:00:00Z' }));
    insertRun(db, makeRun({ id: 'r-third', createdAt: '2026-01-03T10:00:00Z' }));
    insertRun(db, makeRun({ id: 'r-second', createdAt: '2026-01-02T10:00:00Z' }));

    const rows = queryStatusRuns(db);
    expect(rows[0].id).toBe('r-third');
    expect(rows[1].id).toBe('r-second');
    expect(rows[2].id).toBe('r-first');
  });

  test('returns batchId for grouping by batch', () => {
    insertRun(db, makeRun({ id: 'r-batched', batchId: 'batch-xyz' }));
    const rows = queryStatusRuns(db);
    expect(rows[0].batchId).toBe('batch-xyz');
  });

  test('returns all runs (no limit by default)', () => {
    for (let i = 0; i < 20; i++) {
      insertRun(db, makeRun({ id: `r-${i}` }));
    }
    const rows = queryStatusRuns(db);
    expect(rows.length).toBe(20);
  });

  test('includes all required fields for status display', () => {
    insertRun(db, makeRun({ id: 'r-status', specPath: 'specs/test.md', model: 'opus', status: 'success', costUsd: 1.23 }));
    const rows = queryStatusRuns(db);
    const row = rows[0];
    expect(row.id).toBe('r-status');
    expect(row.specPath).toBe('specs/test.md');
    expect(row.model).toBe('opus');
    expect(row.status).toBe('success');
    expect(row.costUsd).toBe(1.23);
    expect(row.startedAt).toBeDefined(); // mapped from createdAt
  });
});

// ── backfillRuns ──────────────────────────────────────────────

describe('backfillRuns', () => {
  let tmpDir: string;

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-runs-backfill-'));
    await fs.mkdir(path.join(tmpDir, '.forge', 'results', '2026-01-01T10-00-00-000Z'), { recursive: true });
  });

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true });
  });

  test('imports summary.json files into runs table', async () => {
    const db = getTestDb();
    const summary = {
      specPath: 'specs/auth.md',
      model: 'claude-opus-4-5',
      status: 'success',
      costUsd: 0.10,
      durationSeconds: 30,
      numTurns: 5,
      toolCalls: 3,
      runId: 'batch-001',
      type: 'run',
      prompt: 'test prompt',
      cwd: tmpDir,
      sessionId: 'sess-abc',
      startedAt: '2026-01-01T10:00:00.000Z',
    };
    await fs.writeFile(
      path.join(tmpDir, '.forge', 'results', '2026-01-01T10-00-00-000Z', 'summary.json'),
      JSON.stringify(summary),
    );

    const count = await backfillRuns(db, tmpDir);
    expect(count).toBe(1);

    const rows = queryStatusRuns(db);
    expect(rows.length).toBe(1);
    expect(rows[0].specPath).toBe('specs/auth.md');
    expect(rows[0].id).toBe('2026-01-01T10-00-00-000Z'); // dir name as id
    db.close();
  });

  test('uses timestamp directory name as run ID', async () => {
    const db = getTestDb();
    await fs.writeFile(
      path.join(tmpDir, '.forge', 'results', '2026-01-01T10-00-00-000Z', 'summary.json'),
      JSON.stringify({ model: 'opus', status: 'success', durationSeconds: 1, prompt: 'p', cwd: '/c', startedAt: '2026-01-01T10:00:00Z' }),
    );

    await backfillRuns(db, tmpDir);
    const rows = queryStatusRuns(db);
    expect(rows[0].id).toBe('2026-01-01T10-00-00-000Z');
    db.close();
  });

  test('is idempotent (INSERT OR IGNORE)', async () => {
    const db = getTestDb();
    await fs.writeFile(
      path.join(tmpDir, '.forge', 'results', '2026-01-01T10-00-00-000Z', 'summary.json'),
      JSON.stringify({ model: 'opus', status: 'success', durationSeconds: 1, prompt: 'p', cwd: '/c', startedAt: '2026-01-01T10:00:00Z' }),
    );

    await backfillRuns(db, tmpDir);
    await backfillRuns(db, tmpDir); // second call should not duplicate
    const rows = queryStatusRuns(db);
    expect(rows.length).toBe(1);
    db.close();
  });

  test('returns 0 when results directory does not exist', async () => {
    const db = getTestDb();
    const count = await backfillRuns(db, path.join(tmpDir, 'nonexistent'));
    expect(count).toBe(0);
    db.close();
  });

  test('skips corrupt summary.json files', async () => {
    const db = getTestDb();
    await fs.writeFile(
      path.join(tmpDir, '.forge', 'results', '2026-01-01T10-00-00-000Z', 'summary.json'),
      '{ invalid json',
    );

    const count = await backfillRuns(db, tmpDir);
    expect(count).toBe(0);
    db.close();
  });

  test('maps runId field to batchId column', async () => {
    const db = getTestDb();
    await fs.writeFile(
      path.join(tmpDir, '.forge', 'results', '2026-01-01T10-00-00-000Z', 'summary.json'),
      JSON.stringify({ model: 'opus', status: 'success', durationSeconds: 1, prompt: 'p', cwd: '/c', startedAt: '2026-01-01T10:00:00Z', runId: 'batch-test-123' }),
    );

    await backfillRuns(db, tmpDir);
    const rows = queryStatusRuns(db);
    expect(rows[0].batchId).toBe('batch-test-123');
    db.close();
  });
});

// ── getDbWithBackfill ─────────────────────────────────────────

describe('getDbWithBackfill', () => {
  let tmpDir: string;

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-backfill-lazy-'));
    await fs.mkdir(path.join(tmpDir, '.forge'), { recursive: true });
  });

  afterEach(async () => {
    closeDb(tmpDir);
    await fs.rm(tmpDir, { recursive: true, force: true });
  });

  test('returns a database instance', async () => {
    const db = await getDbWithBackfill(tmpDir);
    expect(db).not.toBeNull();
  });

  test('triggers backfill when runs table is empty and results exist', async () => {
    // Create a result directory with a summary
    await fs.mkdir(path.join(tmpDir, '.forge', 'results', '2026-01-01T10-00-00-000Z'), { recursive: true });
    await fs.writeFile(
      path.join(tmpDir, '.forge', 'results', '2026-01-01T10-00-00-000Z', 'summary.json'),
      JSON.stringify({ model: 'opus', status: 'success', durationSeconds: 1, prompt: 'p', cwd: tmpDir, startedAt: '2026-01-01T10:00:00Z' }),
    );

    const db = await getDbWithBackfill(tmpDir);
    expect(db).not.toBeNull();
    const rows = queryStatusRuns(db!);
    expect(rows.length).toBe(1);
  });
});
